// HasObjective applies the HasEdge predicate on the "objective" edge.
func HasObjective() predicate.KeyResult {
	return predicate.KeyResult(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ObjectiveTable, ObjectiveColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasObjectiveWith applies the HasEdge predicate on the "objective" edge with a given conditions (other predicates).
func HasObjectiveWith(preds ...predicate.Objective) predicate.KeyResult {
	return predicate.KeyResult(func(s *sql.Selector) {
		step := newObjectiveStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

