// And groups predicates with the AND operator between them.
func And(predicates ...predicate.KeyResult) predicate.KeyResult {
	return predicate.KeyResult(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.KeyResult) predicate.KeyResult {
	return predicate.KeyResult(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.KeyResult) predicate.KeyResult {
	return predicate.KeyResult(sql.NotPredicates(p))
}
